import { describe, it } from "node:test";
import { strict as assert } from "node:assert/strict";
import { getUsers, getUserById } from "../src/routes/users.js";

describe("users", () => {
  it("getUsers returns an array with expected user shape", () => {
    const users = getUsers();
    assert.ok(Array.isArray(users));
    assert.ok(users.length > 0);
    for (const u of users) {
      assert.ok("id" in u && "name" in u);
    }
  });

  it("getUserById returns the matching user", () => {
    const user = getUserById(1);
    assert.notStrictEqual(user, null);
    assert.strictEqual(user.id, 1);
    assert.ok("name" in user);
  });

  it("getUserById returns null for unknown id", () => {
    const user = getUserById(999);
    assert.strictEqual(user, null);
  });
});

import { describe, it } from "node:test";
import { strict as assert } from "node:assert/strict";
import { getPosts, createPost } from "../src/routes/posts.js";

describe("posts", () => {
  it("getPosts returns an array with expected post shape", () => {
    const posts = getPosts();
    assert.ok(Array.isArray(posts));
    assert.ok(posts.length > 0);
    for (const p of posts) {
      assert.ok("id" in p && "title" in p && "body" in p);
    }
  });

  it("createPost returns a new post with correct fields", () => {
    const post = createPost("Test title", "Test body");
    assert.notStrictEqual(post, null);
    assert.strictEqual(post.title, "Test title");
    assert.strictEqual(post.body, "Test body");
    assert.ok(typeof post.id === "number");
  });
});

import { describe, it } from "node:test";
import { strict as assert } from "node:assert/strict";
import { getHealth } from "../src/routes/health.js";

describe("health", () => {
  it("getHealth returns object with status and uptime", () => {
    const health = getHealth();
    assert.notStrictEqual(health, null);
    assert.strictEqual(health.status, "ok");
    assert.ok(typeof health.uptime === "number");
    assert.ok(health.uptime >= 0);
  });
});

